content.content:
1	:root {
2	  --primary-color: #409eff;
3	  --primary-light: #66b1ff;
4	  --primary-dark: #3a8ee6;
5	  --success-color: #67c23a;
6	  --warning-color: #e6a23c;
7	  --danger-color: #f56c6c;
8	  --info-color: #909399;
9	
10	  --bg-primary: #ffffff;
11	  --bg-secondary: #f5f7fa;
12	  --bg-dark: #1e1e2e;
13	  --bg-sidebar: #304156;
14	
15	  --text-primary: #303133;
16	  --text-regular: #606266;
17	  --text-secondary: #909399;
18	  --text-placeholder: #c0c4cc;
19	
20	  --border-color: #dcdfe6;
21	  --border-light: #e4e7ed;
22	  --border-lighter: #ebeef5;
23	
24	  --shadow-sm: 0 2px 4px rgba(0, 0, 0, 0.06);
25	  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.08);
26	  --shadow-lg: 0 8px 24px rgba(0, 0, 0, 0.12);
27	
28	  --radius-sm: 4px;
29	  --radius-md: 8px;
30	  --radius-lg: 12px;
31	
32	  --header-height: 56px;
33	  --sidebar-width: 220px;
34	  --sidebar-collapsed-width: 64px;
35	}
36	
37	* {
38	  margin: 0;
39	  padding: 0;
40	  box-sizing: border-box;
41	}
42	
43	html,
44	body {
45	  width: 100%;
46	  height: 100%;
47	  font-family: 'Helvetica Neue', Helvetica, 'PingFang SC', 'Hiragino Sans GB',
48	    'Microsoft YaHei', '微软雅黑', Arial, sans-serif;
49	  font-size: 14px;
50	  color: var(--text-primary);
51	  background-color: var(--bg-secondary);
52	  -webkit-font-smoothing: antialiased;
53	  -moz-osx-font-smoothing: grayscale;
54	}
55	
56	#app {
57	  width: 100%;
58	  height: 100%;
59	}
60	
61	a {
62	  color: var(--primary-color);
63	  text-decoration: none;
64	
65	  &:hover {
66	    color: var(--primary-light);
67	  }
68	}
69	
70	::-webkit-scrollbar {
71	  width: 6px;
72	  height: 6px;
73	}
74	
75	::-webkit-scrollbar-track {
76	  background: transparent;
77	}
78	
79	::-webkit-scrollbar-thumb {
80	  background-color: #c1c1c1;
81	  border-radius: 3px;
82	
83	  &:hover {
84	    background-color: #a8a8a8;
85	  }
86	}
87	
88	.fade-enter-active,
89	.fade-leave-active {
90	  transition: opacity 0.3s ease;
91	}
92	
93	.fade-enter-from,
94	.fade-leave-to {
95	  opacity: 0;
96	}
97	
98	.slide-right-enter-active,
99	.slide-right-leave-active {
100	  transition: transform 0.3s ease;
101	}
102	
103	.slide-right-enter-from,
104	.slide-right-leave-to {
105	  transform: translateX(100%);
106	}
107	
108	// Utility classes
109	.flex {
110	  display: flex;
111	}
112	
113	.flex-center {
114	  display: flex;
115	  align-items: center;
116	  justify-content: center;
117	}
118	
119	.flex-between {
120	  display: flex;
121	  align-items: center;
122	  justify-content: space-between;
123	}
124	
125	.flex-1 {
126	  flex: 1;
127	}
128	
129	.text-ellipsis {
130	  overflow: hidden;
131	  text-overflow: ellipsis;
132	  white-space: nowrap;
133	}
134	
135	.mt-8 { margin-top: 8px; }
136	.mt-16 { margin-top: 16px; }
137	.mt-24 { margin-top: 24px; }
138	.mb-8 { margin-bottom: 8px; }
139	.mb-16 { margin-bottom: 16px; }
140	.ml-8 { margin-left: 8px; }
141	.mr-8 { margin-right: 8px; }
142	.p-16 { padding: 16px; }
143	.p-24 { padding: 24px; }
